   276→// Алгоритм чесності Provably Fair
   277→function openCaseProvablyFair(items, serverSeed, clientSeed, nonce) {
   278→  const combinedString = `${serverSeed}-${clientSeed}-${nonce}`;
   279→  const hash = crypto.createHash('sha256').update(combinedString).digest('hex');
   280→  const hexSubstring = hash.substring(0, 8);
   281→  const intNumber = parseInt(hexSubstring, 16);
   282→  const randomNumber = (intNumber / 4294967295) * 100;
   283→
   284→  let currentBound = 0;
   285→  for (let i = 0; i < items.length; i++) {
   286→    const item = items[i];
   287→    currentBound += item.chance;
   288→    if (randomNumber <= currentBound) {
   289→      return { item, hash, randomNumber };
   290→    }
   291→  }
   292→
   293→  // Fallback: if rounding or malformed chances skip selection, return the last item
   294→  return { item: items[items.length - 1], hash, randomNumber };
   295→}
