   297→// API: Відкриття кейсу (POST з ACID-транзакцією та справжнім Provably Fair)
   298→app.post('/api/open-case', openCaseLimiter, isAuthenticated, async (req, res) => {
   299→  const { caseId, clientSeed } = req.body;
   300→  const userId = req.session.userId;
   301→
   302→  try {
   303→    const currentCase = await prisma.case.findUnique({
   304→      where: { id: caseId },
   305→      include: { items: true }
   306→    });
   307→
   308→    if (!currentCase) {
   309→      return res.status(404).json({ success: false, message: "Кейс не знайдено." });
   310→    }
   311→
   312→    const result = await prisma.$transaction(async (tx) => {
   313→      const user = await tx.user.findUnique({ where: { id: userId } });
   314→
   315→      if (user.balance < currentCase.price) {
   316→        throw new Error("Недостатньо балів на балансі, бро!");
   317→      }
   318→
   319→      const balanceAfterBuy = user.balance - currentCase.price;
   320→      
   321→      // Справжній Provably Fair 
   322→      const serverSeed = process.env.SERVER_SEED || "fallback_server_seed";
   323→      const nonce = user.nonce; // Беремо точний порядковий номер гри юзера з БД
   324→      const userSeed = clientSeed || "default_bro_seed";
   325→      
   326→      const dropResult = openCaseProvablyFair(currentCase.items, serverSeed, userSeed, nonce);
   327→      const finalBalance = balanceAfterBuy + dropResult.item.price;
   328→
   329→      // Оновлюємо баланс та ЗБІЛЬШУЄМО nonce на 1
   330→      await tx.user.update({
   331→        where: { id: userId },
   332→        data: { 
   333→          balance: balanceAfterBuy,
   334→          nonce: { increment: 1 } // Наступна гра матиме новий хеш
   335→        }
   336→      });
   337→
   338→      const newInventoryItem = await tx.inventory.create({
   339→        data: {
   340→          userId: user.id,
   341→          itemId: dropResult.item.id,
   342→          status: "IN_INVENTORY"
   343→        }
   344→      });
   345→
   346→      return {
   347→        drop: dropResult.item,
   348→        hash: dropResult.hash,
   349→        randomNumber: dropResult.randomNumber,
   350→        previousBalance: user.balance,
   351→        balanceAfterBuy,
   352→        finalBalance: balanceAfterBuy,
   353→        inventoryId: newInventoryItem.id,
   354→        nonce: nonce                      
   355→      };
   356→    });
   357→
   358→    res.json({
   359→      success: true,
   360→      caseTitle: currentCase.title,
   361→      casePrice: currentCase.price,
   362→      user: {
   363→        previousBalance: result.previousBalance.toFixed(2),
   364→        balanceAfterBuy: result.balanceAfterBuy.toFixed(2),
   365→        finalBalance: result.finalBalance.toFixed(2)
   366→      },
   367→      drop: result.drop,
   368→      inventoryId: result.inventoryId,
   369→      provablyFair: { hash: result.hash, number: result.randomNumber.toFixed(4), nonce: result.nonce }
   370→    });
   371→
   372→  } catch (error) {
   373→    res.status(400).json({ success: false, message: error.message });
   374→  }
   375→});
