   412→// API: Активація промокоду для поповнення балансу (Транзакційно)
   413→app.post('/api/promo/activate', isAuthenticated, async (req, res) => {
   414→  const { code } = req.body;
   415→  const userId = req.session.userId;
   416→
   417→  if (!code || code.trim() === "") {
   418→    return res.status(400).json({ success: false, message: "Введіть промокод!" });
   419→  }
   420→
   421→  try {
   422→    const result = await prisma.$transaction(async (tx) => {
   423→      // 1. Шукаємо промокод
   424→      const promo = await tx.promoCode.findUnique({
   425→        where: { code: code.toUpperCase().trim() },
