   431→      }
   432→
   433→      // 2. Перевіряємо загальний ліміт використань
   434→      if (promo.activations.length >= promo.maxUses) {
   435→        throw new Error("Цей промокод уже вичерпав свій ліміт!");
   436→      }
   437→
   438→      // 3. Перевіряємо, чи цей користувач його вже не активував
   439→      const alreadyActivated = promo.activations.some(act => act.userId === userId);
