   459→  // ФІЛЬТРАЦІЯ ТА СОРТУВАННЯ СКІНІВ
   460→  function applyInventoryFilters() {
   461→    const rarityFilter = document.getElementById('filterRarity').value;
   462→    const sortFilter = document.getElementById('filterSort').value;
   463→    
   464→    let filtered = currentInventoryArray.filter(record => {
   465→      if (rarityFilter === 'all') return true;
   466→      if (rarityFilter === 'rare') return record.item.chance < 2;
   467→      if (rarityFilter === 'classified') return record.item.chance >= 2 && record.item.chance < 15;
   468→      if (rarityFilter === 'common') return record.item.chance >= 15;
   469→      return true;
   470→    });
   471→
   472→    if (sortFilter === 'price-desc') {
   473→      filtered.sort((a, b) => b.item.price - a.item.price);
   474→    } else if (sortFilter === 'price-asc') {
   475→      filtered.sort((a, b) => a.item.price - b.item.price);
   476→    } else if (sortFilter === 'date-desc') {
   477→      filtered.sort((a, b) => new Date(b.droppedAt) - new Date(a.droppedAt));
   478→    }
   479→
   480→    renderProfileInventory(filtered);
   481→  }
