   495→        
   496→        let borderNeon = 'border-gray-700 shadow-[inset_0_0_10px_rgba(0,0,0,0.5)]';
   497→        if (item.chance < 2) borderNeon = 'border-red-500 shadow-[0_0_15px_rgba(239,68,68,0.15)]';
