      role: user.role,
      nonce: user.nonce,
      createdAt: user.createdAt,
      tradeUrl: user.tradeUrl,
      stats: {
        currentItems: currentInventoryCount,
        totalSold: soldInventoryCount,
      },
    });
  } catch (error) {
    console.error(error);
    return NextResponse.json({ success: false, message: 'Failed to load profile.' }, { status: 500 });
